import { Component, computed, inject, OnInit, signal } from '@angular/core';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { CourseService } from '../../../core/services/course.service';
import { AuthService } from '../../../core/services/auth.service';
import { ToastService } from '../../../core/services/toast.service';
import { ConfirmService } from '../../../core/services/confirm.service';
import { CoursePageSummaryDto, PageContentType } from '../../../core/models/course.models';
import { CourseNavComponent } from '../../../shared/course-nav/course-nav';

/**
 * Course pages index — /courses/:courseId/pages
 * Lists every page in the course with a "New Page" button (admins).
 * Replaces the former in-modal pages list.
 */
@Component({
  selector: 'app-course-pages',
  standalone: true,
  imports: [RouterLink, CourseNavComponent],
  template: `
    <div class="course-layout">
      <app-course-nav [courseId]="courseId()" active="pages" />

      <main class="course-main">
      <div class="cp-head">
        <a [routerLink]="['/courses', courseId()]" class="back-link">
          <span class="material-icons">arrow_back</span> Back to course
        </a>
        <div class="cp-title-row">
          <h1>Pages</h1>
          @if (isAdmin()) {
            <a class="btn btn-primary btn-sm" [routerLink]="['/courses', courseId(), 'pages', 'new']">
              <span class="material-icons" style="font-size:16px;">add</span> New Page
            </a>
          }
        </div>
      </div>

      @if (loading()) {
        <div class="loading-spinner"><div class="spinner"></div></div>
      } @else {
        <div class="card">
          <p class="hint">
            Pages hold all your content — lessons, videos, files, and any free-form material.
          </p>
          <div class="pages-list">
            @for (p of pages(); track p.id) {
              <div class="page-row" (click)="open(p)">
                <span class="material-icons">{{ pageIcon(p.contentType) }}</span>
                <div class="page-main">
                  <strong>{{ p.title }}</strong>
                  @if (p.durationMinutes) { <span class="page-meta">{{ p.durationMinutes }} min</span> }
                </div>
                @if (p.isFrontPage) { <span class="badge badge-success">Front Page</span> }
                @if (isAdmin() && !p.isPublished) { <span class="badge badge-gray">Draft</span> }
                @if (isAdmin()) {
                  <div class="page-actions" (click)="$event.stopPropagation()">
                    <button class="icon-btn" (click)="togglePublished(p)"
                            [title]="p.isPublished ? 'Unpublish' : 'Publish'">
                      <span class="material-icons">{{ p.isPublished ? 'visibility' : 'visibility_off' }}</span>
                    </button>
                    <button class="icon-btn" (click)="makeFrontPage(p)" title="Use as course home page"
                            [disabled]="p.isFrontPage">
                      <span class="material-icons">home</span>
                    </button>
                    <button class="icon-btn icon-btn-danger" (click)="remove(p)" title="Delete page">
                      <span class="material-icons">delete</span>
                    </button>
                  </div>
                }
              </div>
            } @empty {
              <div class="empty-state"><span class="material-icons">description</span>
                @if (isAdmin()) {
                  <p>No pages yet. Create one for each lesson, video, or piece of reading material.</p>
                } @else {
                  <p>No pages available yet.</p>
                }
              </div>
            }
          </div>
        </div>
      }
      </main>
    </div>
  `,
  styleUrl: './course-pages.scss',
})
export class CoursePagesComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private cSvc = inject(CourseService);
  private auth = inject(AuthService);
  private toast = inject(ToastService);
  private confirm = inject(ConfirmService);

  readonly courseId = signal(0);
  readonly pages = signal<CoursePageSummaryDto[]>([]);
  readonly loading = signal(true);
  readonly isAdmin = computed(() => this.auth.hasRole('PlatformAdmin', 'Instructor'));

  ngOnInit(): void {
    this.courseId.set(Number(this.route.snapshot.paramMap.get('courseId')));
    this.load();
  }

  private load(): void {
    this.loading.set(true);
    this.cSvc.getPages(this.courseId()).subscribe({
      next: pages => { this.pages.set(pages); this.loading.set(false); },
      error: (e: Error) => { this.loading.set(false); this.toast.error(`Failed to load pages: ${e.message}`); },
    });
  }

  open(p: CoursePageSummaryDto): void {
    this.router.navigate(['/courses', this.courseId(), 'pages', p.id]);
  }

  pageIcon(type: PageContentType): string {
    return type === 'Video' ? 'play_circle' : type === 'File' ? 'description' : 'article';
  }

  togglePublished(p: CoursePageSummaryDto): void {
    this.cSvc.setPagePublished(p.id, !p.isPublished).subscribe({
      next: () => { this.toast.success(p.isPublished ? 'Page unpublished.' : 'Page published.'); this.load(); },
      error: (e: Error) => this.toast.error(`Failed to update page: ${e.message}`),
    });
  }

  makeFrontPage(p: CoursePageSummaryDto): void {
    this.cSvc.setPageAsFrontPage(p.id).subscribe({
      next: () => { this.toast.success(`"${p.title}" is now the course home page.`); this.load(); },
      error: (e: Error) => this.toast.error(`Failed to set home page: ${e.message}`),
    });
  }

  async remove(p: CoursePageSummaryDto): Promise<void> {
    const ok = await this.confirm.ask({
      title: 'Delete page',
      message: `Delete "${p.title}"? Any module items that reference this page will also be removed.`,
      confirmLabel: 'Delete',
      danger: true,
    });
    if (!ok) return;
    this.cSvc.deletePage(p.id).subscribe({
      next: () => { this.toast.success('Page deleted.'); this.load(); },
      error: (e: Error) => this.toast.error(`Failed to delete page: ${e.message}`),
    });
  }
}
